#include <cstdio>
#include <cstdint>
#include <cmath>
#include <limits>
#include "json.hpp"
using json = nlohmann::json;

int main(int argc, const char * argv[])
{
    const json::number_float_t float_reference{ std::numeric_limits<json::number_float_t>::max() };
    json j(float_reference);

    int n_int = j.get<int>();
    if (n_int != std::numeric_limits<int>::max())
        fprintf(stderr,"ERROR - int from float failed! Got %d instead of %d\n", n_int, std::numeric_limits<int>::max());

    uint64_t n_int64 = j.get<uint64_t>();
    if (n_int64 != std::numeric_limits<uint64_t>::max())
        fprintf(stderr,"ERROR - uint64 from float failed! Got %llu instead of %llu\n", n_int64, std::numeric_limits<uint64_t>::max());

    // Inf and NaN fail with undefined behavior
    // integer overrange also fails with bit aliasing behavior (might as well be random)
    // See the updated unit-conversions.cpp for the fill list of problems and tests
    return 0;
}
```

